INSERT INTO _recipe_steps_patch ("RecipeId", "StepsJson") VALUES
('25bc1a94-c562-5426-abbe-f81176ee4d63'::uuid, '["220 g Domates, 120 g Kapya Biber malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","10 g Maydanoz, 70 g Soğan malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 2 g Kırmızı Biber, 8 ml Nar Ekşisi, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('5971f846-0fdd-56d9-9603-e02534c03829'::uuid, '["Hazırlık için 70 g Arpa Şehriye ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 80 g Havuç, 80 g Kabak, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","70 g Arpa Şehriye tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('7e0e56f6-dee2-5cc5-8b9b-49be541f64de'::uuid, '["Hazırlık için 60 g Arpa Şehriye, 190 g Yoğurt ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 1 adet Yumurta eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 2 g Nane, 7 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","60 g Arpa Şehriye, 190 g Yoğurt tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('e6bc6caa-1bdb-5b81-81d5-85168f551026'::uuid, '["Hazırlık için 220 g Bamya ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 140 g Domates, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 8 ml Limon, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","220 g Bamya tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('29e53d46-d0d4-58a4-ab6b-d8653b378a09'::uuid, '["220 g Barbunya, 100 g Soğan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Domates, 110 g Havuç malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","20 g Domates Salçası, 1 g Karabiber, 14 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('35926b19-1921-5557-99fc-1b3d8c700ae8'::uuid, '["200 g Barbunya malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","110 g Kapya Biber, 12 g Maydanoz malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 10 ml Limon, 12 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('dd1c98e4-edc2-5d73-8232-a72bd01f55a6'::uuid, '["220 g Domates, 70 g Soğan, 120 g Yeşil Biber, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","45 g Beyaz Peynir, 60 g Kabak malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Kırmızı Biber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('f31b85c2-3d88-504e-b637-c44a184f1634'::uuid, '["100 g Soğan, 260 g Tavuk Göğsü malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 160 g Domates, 1 g Karabiber, 2 g Kekik, 14 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","120 g Baklavalık Yufka, 120 g Yoğurt malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('e5454fa1-d669-512c-b884-198bc473cdef'::uuid, '["220 g Kapya Biber, 180 g Yoğurt malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","8 g Sarımsak malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('1fd50683-b1c3-59da-a497-e585b65aa8b7'::uuid, '["200 g Börülce malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","140 g Domates, 12 g Maydanoz malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 12 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('a2138b00-e5de-5486-8703-1d90a00a2349'::uuid, '["220 g Börülce, 100 g Soğan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Domates, 110 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","20 g Domates Salçası, 1 g Karabiber, 14 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('708a569c-1137-5867-a7d1-8f1df9a7a803'::uuid, '["Hazırlık için 280 g Brokoli ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 80 g Patates, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 10 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","280 g Brokoli tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('a064ba94-63a6-5162-b0f5-1254053ca0b4'::uuid, '["70 g Brokoli, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Beyaz Peynir malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 2 g Dereotu, 1 g Karabiber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('249b9a96-27b0-5f58-bfc7-550340467176'::uuid, '["260 g Brokoli, 45 g Un, 2 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","45 g Kaşar Peyniri, 70 g Soğan malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 6 g Dereotu, 3 g Nane, 10 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('e6fac80a-8d22-5179-96d0-939b53bf1a2c'::uuid, '["220 g Bulgur, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 8 g Tereyağı, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Pazı, 110 g Soğan malzemelerini ekleyip birkaç dakika sotele.","220 g Bulgur, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('ce23f4b7-1db4-5a87-8cb8-595103a30544'::uuid, '["Hazırlık için 60 g Bulgur, 220 g Yoğurt ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Nohut eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 2 g Nane, 7 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","60 g Bulgur, 220 g Yoğurt tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('4734c5db-5ed2-5b65-b638-ee954774b915'::uuid, '["180 g Salatalık, 260 g Yoğurt malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","8 g Sarımsak malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 2 g Nane, 6 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('b6667ce1-667f-53c8-8ba4-50c9b1e829ab'::uuid, '["220 g Kereviz, 160 g Yoğurt malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","25 g Ceviz malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('3c67e99e-3947-5ba8-b402-34bbc50bebb2'::uuid, '["220 g Pancar, 170 g Yoğurt malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","25 g Ceviz, 8 g Sarımsak malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('5fece78d-864d-5a92-bb81-e23a62d03169'::uuid, '["180 g Pazı malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","25 g Ceviz, 50 g Soğan malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('d7d08dc4-b094-5f42-a1db-9fb9a9cd1b4d'::uuid, '["220 g Domates, 160 g Salatalık malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","10 g Maydanoz, 60 g Soğan malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 10 ml Limon, 12 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('b5e736be-a1e6-552e-82c4-e7f8f8c542a7'::uuid, '["Hazırlık için 320 g Domates ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 10 g Sarımsak, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 8 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","320 g Domates tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('d4014e83-d770-5333-9740-98a695cc69a2'::uuid, '["220 g Bulgur, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 8 g Tereyağı, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Domates, 110 g Kapya Biber malzemelerini ekleyip birkaç dakika sotele.","220 g Bulgur, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('be0a5866-b2cd-5823-9b6c-37e7f9a12032'::uuid, '["220 g Erişte, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Domates, 110 g Yeşil Mercimek malzemelerini ekleyip birkaç dakika sotele.","220 g Erişte, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('4b2acd99-1214-5bfc-9655-1fb94e53e58c'::uuid, '["Hazırlık için 260 g Domates, 65 g Tel Şehriye ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 60 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 7 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","260 g Domates, 65 g Tel Şehriye tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('b7ea4bea-6e05-5216-bcfe-afb9d27f1176'::uuid, '["70 g Soğan, 220 g Tam Buğday Makarnası malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Domates, 110 g Kapya Biber malzemelerini ekleyip birkaç dakika sotele.","70 g Soğan, 220 g Tam Buğday Makarnası ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('adf00d50-924d-59f0-89d4-b9189b475c9c'::uuid, '["380 g Patlıcan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","160 g Domates, 90 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","10 ml Limon, 18 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('e7b5b438-bad7-5c97-99b7-9591deac65ef'::uuid, '["Hazırlık için 60 g Erişte, 130 g Yeşil Mercimek ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 100 g Domates, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 15 g Domates Salçası, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","60 g Erişte, 130 g Yeşil Mercimek tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('9027e1bd-4f3d-55b7-af70-56241db0ff43'::uuid, '["100 g Soğan, 220 g Yeşil Mercimek malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 20 g Domates Salçası, 1 g Karabiber, 14 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Havuç malzemelerini ekleyip birkaç dakika sotele.","100 g Soğan, 220 g Yeşil Mercimek ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('05f39652-3c86-5e5f-a2f4-42b06e657e26'::uuid, '["220 g Bamya, 180 g Dana Kuşbaşı, 100 g Soğan malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 20 g Domates Salçası, 1 g Karabiber, 14 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","110 g Domates, 110 g Soğan malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
