('d44d6ab3-eff5-5b37-8910-a7aa747c2a79'::uuid, '["320 g Somon malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","110 g Brokoli, 110 g Kabak, 110 g Kapya Biber malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('9485c8dd-a562-547b-ab42-f2c91baa5048'::uuid, '["220 g Domates, 140 g Salatalık malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","30 g Ceviz, 10 g Maydanoz, 50 g Soğan malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Nar Ekşisi, 2 g Sumak, 12 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('16480fe6-c632-5b1d-a36d-8189cc279ad0'::uuid, '["320 g Hamsi malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Domates, 110 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('2417e94a-b3e3-544f-906a-e18c10a5f72e'::uuid, '["320 g Hamsi malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","110 g Kapya Biber, 110 g Soğan malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('1825a46b-9b2b-531a-9507-cd1030744087'::uuid, '["260 g Kabak, 45 g Un, 2 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","45 g Cottage Cheese, 70 g Havuç malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 6 g Dereotu, 3 g Nane, 10 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('fe0a4aa8-5b97-5021-a184-7438b7cd0dd3'::uuid, '["70 g Havuç, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Cottage Cheese malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 2 g Dereotu, 1 g Karabiber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('fc51a95b-7368-5540-a2f8-3c0970b92843'::uuid, '["Hazırlık için 115 g Tarhana ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 90 g Havuç, 60 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Kırmızı Biber, 7 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","115 g Tarhana tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('260f9039-b7eb-55d1-b114-42bf33865a6f'::uuid, '["70 g Beyaz Peynir, 220 g Süzme Yoğurt malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","8 g Sarımsak malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","2 g Nane, 6 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('65ed96df-b1d3-5680-96df-306d8a8f3626'::uuid, '["70 g Kapya Biber, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Hellim malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Karabiber, 2 g Maydanoz, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('011be114-eecb-5cb1-aefd-726e486afb76'::uuid, '["220 g Baldo Pirinç, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 8 g Tereyağı, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Çam Fıstığı, 110 g Kuş Üzümü malzemelerini ekleyip birkaç dakika sotele.","220 g Baldo Pirinç, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('f6040a9d-0ba8-5390-9d87-5602c397a9bf'::uuid, '["420 g Patlıcan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","180 g Domates, 12 g Sarımsak, 120 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","10 ml Limon, 18 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('e150cc19-1843-52b5-adf3-6bbedec41bdc'::uuid, '["Hazırlık için 240 g Ispanak ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 90 g Patates, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","240 g Ispanak tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
