('21e053e0-b90c-5bf6-8251-2c2238968e98'::uuid, '["Hazırlık için 180 g Mercimek ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 80 g Havuç, 110 g Patates eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 15 g Domates Salçası, 2 g Kimyon, 10 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","180 g Mercimek tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('fbeaedcd-da7a-5da0-8247-1dfcce81eb38'::uuid, '["Hazırlık için 260 g Domates, 160 g Kapya Biber ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 10 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","260 g Domates, 160 g Kapya Biber tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('c2555fa4-cb32-5e9c-8534-5d7a22ae3c97'::uuid, '["260 g Kapya Biber malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","10 g Maydanoz, 8 g Sarımsak malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('9f511808-73c7-5cea-860d-8f4c0fa84e6c'::uuid, '["Hazırlık için 280 g Patlıcan ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Soğan, 100 ml Süt eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","280 g Patlıcan tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('55276c52-93d0-5680-9ac8-76aceee99be5'::uuid, '["280 g Patlıcan malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","10 g Maydanoz, 8 g Sarımsak malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('44e78c6d-ede7-5468-99bb-ea984e7b9bc4'::uuid, '["200 g Fasulye malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","12 g Maydanoz, 70 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","8 ml Sirke, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('af62429a-6ea4-5223-95b6-fa6045c08c10'::uuid, '["260 g Kuzu Kuşbaşı, 100 g Soğan malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 160 g Domates, 1 g Karabiber, 2 g Kekik, 14 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","120 g Kabak, 120 g Kapya Biber, 120 g Patlıcan malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
