('45517ef3-8ee7-5661-8701-769fb797958f'::uuid, '["35 g Galeta Unu, 280 g Köftelik Dana Kıyma, 90 g Soğan, 1 adet Yumurta malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 18 g Domates Salçası, 1 g Karabiber, 2 g Kimyon, 10 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","120 g Havuç, 120 g Nohut malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('b17e2289-62f3-588b-bef4-c653993a783f'::uuid, '["Hazırlık için 90 g Nohut, 110 g Tarhana ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Kırmızı Biber, 7 g Tereyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","90 g Nohut, 110 g Tarhana tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('57217dbe-a76b-5c0d-8602-f05200e41cd1'::uuid, '["260 g Dana Kuşbaşı, 100 g Soğan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","120 g Bezelye, 120 g Havuç, 120 g Patates malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","160 g Domates, 1 g Karabiber, 2 g Kekik, 14 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('96c307c7-6d2b-589e-8a47-ac25f40d2f87'::uuid, '["320 g Palamut malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Domates, 110 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('04eb8198-72af-5843-b210-a6e6c422a617'::uuid, '["320 g Palamut malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Roka, 110 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('06bbc6eb-06d7-5c51-b08d-efb7265420a1'::uuid, '["220 g Pancar malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","25 g Ceviz, 120 g Yoğurt malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('a078ee6f-f432-50fe-8bf0-8de585a2980e'::uuid, '["140 g Baklavalık Yufka, 60 g Beyaz Peynir, 70 g Patates malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","1 g Karabiber, 8 g Maydanoz, 8 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('08388259-3025-5f8f-b237-c9adc5a366e9'::uuid, '["140 g Baklavalık Yufka, 60 g Beyaz Peynir, 70 g Patates malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","1 g Karabiber, 8 g Maydanoz, 8 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('2c378560-046f-55de-ade0-0940d179e634'::uuid, '["220 g Domates, 70 g Soğan, 120 g Yeşil Biber, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","60 g Patates malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Kırmızı Biber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('dd641cdb-3921-55c1-ab29-6bb7c6434b74'::uuid, '["70 g Patates, 70 g Soğan, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","Tavayı 1 g Karabiber, 2 g Maydanoz, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('4772a419-deaf-5666-9715-b0540c6a9a21'::uuid, '["260 g Patates, 220 g Tavuk Göğsü malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 1 g Karabiber, 12 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","110 g Domates, 110 g Soğan malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('6074b96a-8f6c-581c-9a79-fbdd5183456e'::uuid, '["260 g Patates, 45 g Un, 2 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","45 g Beyaz Peynir, 70 g Taze Soğan malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 6 g Dereotu, 3 g Nane, 10 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('1a2370f3-8ba6-5868-b495-af385cb26856'::uuid, '["260 g Patates malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","12 g Maydanoz, 60 g Taze Soğan malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 2 g Sumak, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('868ab539-1920-5264-a62f-5172bc24bf5c'::uuid, '["70 g Patlıcan, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Kaşar Peyniri malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Karabiber, 2 g Maydanoz, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
