('c3da09a9-0637-58c2-ae48-fbd1b4104df7'::uuid, '["140 g Baklavalık Yufka, 60 g Beyaz Peynir, 70 g Pırasa malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","1 g Karabiber, 8 g Maydanoz, 8 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('a572bc1e-dee9-5e89-bcb4-749942589233'::uuid, '["380 g Kereviz malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","100 g Havuç, 80 ml Portakal Suyu malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","10 ml Limon, 18 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('28468d02-fb75-530d-9361-5e0889d37b12'::uuid, '["320 g Ton Balığı malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","110 g Domates, 110 g Roka malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","1 g Karabiber, 2 g Kekik, 10 ml Limon, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('b67da8d9-0b74-50e7-8aa6-fc552a9f8dfd'::uuid, '["150 g Domates, 120 g Roka malzemelerini yıka, ayıkla ve tarif dokusuna uygun şekilde doğra, rendele veya ez.","60 g Beyaz Peynir malzemelerini eklenmeye hazır hale getir; salata/meze dokusunu bozmayacak incelikte hazırla.","Sos için 8 ml Limon, 10 ml Zeytinyağı malzemelerini küçük bir kapta homojen olana kadar karıştır.","Hazırlanan ana malzemeleri geniş bir kapta birleştir; sosu ekleyip ezmeden karıştır.","Lezzetin oturması için kısa süre dinlendir, ardından soğuk veya oda sıcaklığında servis et."]'),
('4c6b91b3-c5a0-54c1-8805-be8172d4b370'::uuid, '["70 g Roka, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Beyaz Peynir malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Karabiber, 2 g Maydanoz, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('fb924281-d9f5-5191-b038-b9f666b2be78'::uuid, '["180 g Kabak, 220 g Patlıcan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","160 g Domates, 120 g Kapya Biber malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","8 g Sarımsak, 12 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('b001796e-9255-50ff-a628-dd42d04942d3'::uuid, '["220 g Arpa Şehriye, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Kapya Biber, 110 g Mantar malzemelerini ekleyip birkaç dakika sotele.","220 g Arpa Şehriye, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('f33f89dd-b8aa-50a7-b6c9-77d6d1a018ed'::uuid, '["Hazırlık için 75 g Bulgur ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Havuç, 80 g Kabak, 70 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 14 g Domates Salçası, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","75 g Bulgur tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('5a14b96c-0281-5f62-bb38-933b87fd505a'::uuid, '["220 g Bulgur, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 8 g Tereyağı, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Havuç, 110 g Kabak, 110 g Kapya Biber malzemelerini ekleyip birkaç dakika sotele.","220 g Bulgur, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('591b5afa-b198-551e-bc5b-f30e37ae589a'::uuid, '["260 g Dana Kuşbaşı, 100 g Soğan malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","120 g Kapya Biber, 120 g Mantar, 120 g Soğan malzemelerini tarifin dokusuna uygun biçimde eklenmeye hazır hale getir.","160 g Domates, 1 g Karabiber, 2 g Kekik, 14 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('c535da2e-bcb1-56d5-9eed-35d768a51fe2'::uuid, '["220 g Erişte, 70 g Soğan malzemelerini ölçülü hazırla; tahıl veya makarna grubunu kısa süre sudan geçirip süz.","Tencereye 1 g Karabiber, 12 ml Zeytinyağı alıp ısıt; aromatikleri yakmadan kısa süre kavur.","110 g Kabak, 110 g Kapya Biber, 110 g Mantar malzemelerini ekleyip birkaç dakika sotele.","220 g Erişte, 70 g Soğan ekleyip karıştır; uygun miktarda sıcak su ilave ederek kapağı kapalı şekilde pişir.","Suyunu çekince ocaktan al, 5 dakika dinlendir ve tane tane servis et."]'),
('d0b6c9bb-008f-596e-96b2-ad563606c336'::uuid, '["260 g Hindi Göğsü, 100 g Soğan malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 160 g Domates, 1 g Karabiber, 2 g Kekik, 14 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","120 g Kabak, 120 g Kapya Biber, 120 g Mantar malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
('a2f6235c-9ea3-5f2e-ae75-9abc68d487af'::uuid, '["35 g Galeta Unu, 280 g Köftelik Dana Kıyma, 90 g Soğan, 1 adet Yumurta malzemelerini ölçülü hazırla; protein grubunu eşit pişecek parçalara ayır.","Marine veya pişirme tabanı için 18 g Domates Salçası, 1 g Karabiber, 2 g Kimyon, 10 ml Zeytinyağı malzemelerini karıştırıp ana malzemeye yedir.","120 g Domates, 120 g Kabak, 120 g Patlıcan malzemelerini ekleyerek sebze ve eşlikçi dengesini kur.","Tava, tencere veya fırında orta ısıda protein tamamen pişene kadar kontrollü şekilde pişir.","Piştikten sonra birkaç dakika dinlendir, porsiyonlayıp sıcak servis et."]'),
