('012d10ff-def6-5f43-afa8-a60c09f4add0'::uuid, '["Hazırlık için 180 g Tavuk Göğsü, 60 g Tel Şehriye ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 70 g Havuç, 60 g Soğan eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 1 g Karabiber, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","180 g Tavuk Göğsü, 60 g Tel Şehriye tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('b6416f48-49ae-5902-9063-f26b695a33a3'::uuid, '["70 g Semizotu, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Beyaz Peynir malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 2 g Dereotu, 1 g Karabiber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('b2fabc07-466e-5a77-a9d0-9ae89e1069c0'::uuid, '["70 g Semizotu, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Hellim malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 2 g Dereotu, 1 g Karabiber, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
('76ad545c-e0e9-5a81-808a-84c379ecfcb2'::uuid, '["140 g Baklavalık Yufka, 70 g Cottage Cheese, 70 g Semizotu malzemelerini ölçülü şekilde hazırla; yıkanacak, doğranacak veya haşlanacak parçaları önceden düzenle.","1 g Karabiber, 8 g Maydanoz, 8 ml Zeytinyağı ile tarifin aroma ve sos tabanını oluştur.","Tüm malzemeleri uygun sırayla birleştirip orta ateşte veya tarif yapısına uygun yöntemle pişir.","Kıvamı ve lezzeti kontrol edip kısa süre dinlendir; ardından porsiyonlayarak servis et."]'),
('6a0664f3-8a4c-58f9-ae4e-659d51616f4a'::uuid, '["Hazırlık için 240 g Semizotu ölçülü şekilde hazırla; sebze veya bakliyat varsa yıka, ayıkla ve küçük parçalara böl.","Lezzeti desteklemek için 40 g Pirinç, 160 g Yoğurt eklenmeye hazır olacak şekilde doğra veya çırp.","Tencereye 2 g Nane, 8 ml Zeytinyağı alıp kısık-orta ateşte kısa süre ısıtarak çorbanın aroma tabanını oluştur.","240 g Semizotu tencereye ekle; üzerini geçecek kadar sıcak su ilave edip malzemeler yumuşayana kadar pişir.","Kıvamı kontrol et, gerekirse sıcak suyla aç; 2-3 dakika dinlendirip sıcak servis et."]'),
('4e357a15-3217-52b9-9466-4780662043c2'::uuid, '["70 g Soğan, 3 adet Yumurta malzemelerini hazırla; sebzeleri küçük doğra veya rendele, yumurtalı karışım varsa pürüzsüz olana kadar çırp.","50 g Kaşar Peyniri malzemelerini karışıma ekle ve homojen dağılmasını sağla.","Tavayı 1 g Karabiber, 2 g Maydanoz, 8 ml Zeytinyağı ile hafifçe yağlayıp ısıt; baharatları son aşamada dengeli ekle.","Karışımı tavaya alıp orta ateşte altı toparlanana kadar pişir; gerekirse çevirerek içinin de pişmesini sağla.","Ocaktan aldıktan sonra 1 dakika dinlendir ve sıcak servis et."]'),
